using Microsoft.EntityFrameworkCore;

// Cosmos DB project fixes for EF Core 9 breaking changes.
// These patterns must be applied to your Cosmos DB project.

class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // FIX 1: Discriminator property renamed from "Discriminator" to "$type" in EF Core 9.
        // Existing documents use "Discriminator" — explicitly configure to preserve compatibility.
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // FIX 2: id property no longer contains discriminator prefix (was "Session|123", now "123").
        // Existing documents have the old compound format — preserve it.
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
    }
}

// FIX 3: Sync I/O no longer supported on the Cosmos DB provider.
// Synchronous calls (ToList, SaveChanges, First, etc.) now throw.
// Convert all queries and save operations to async equivalents.
class CosmosQueryExamples
{
    // BREAKS — ToList() throws on Cosmos DB provider in EF Core 9
    // var sessions = db.Sessions.Where(s => s.IsActive).ToList();

    // Fix — use async
    async Task QueryAsync(CosmosDbContext db)
    {
        var sessions = await db.Sessions.Where(s => s.IsActive).ToListAsync();
        await db.SaveChangesAsync();
    }
}

class Session
{
    public string Id { get; set; } = "";
    public bool IsActive { get; set; }
}

